-- Example table
CREATE TABLE students (
  id INT PRIMARY KEY,
  name VARCHAR(50),
  age INT
);

SELECT orders.id, customers.name
FROM orders
INNER JOIN customers ON orders.customer_id = customers.id;

SELECT customers.name, orders.id
FROM customers
LEFT JOIN orders ON customers.id = orders.customer_id;

SELECT e1.name AS employee, e2.name AS manager
FROM employees e1
JOIN employees e2 ON e1.manager_id = e2.id;

SELECT name FROM employees e
WHERE EXISTS (
  SELECT 1 FROM orders o WHERE o.employee_id = e.id
);

SELECT dept_avg.department, dept_avg.avg_sal
FROM (
  SELECT department, AVG(salary) AS avg_sal
  FROM employees GROUP BY department
) AS dept_avg
WHERE dept_avg.avg_sal > 50000;

SELECT name FROM customers
UNION
SELECT name FROM suppliers;

SELECT name, salary,
  RANK() OVER (ORDER BY salary DESC) AS salary_rank
FROM employees;

SELECT name, department,
  ROW_NUMBER() OVER (PARTITION BY department ORDER BY salary DESC) AS rn
FROM employees;

SELECT order_date, amount,
  SUM(amount) OVER (ORDER BY order_date) AS running_total
FROM orders;

SELECT name, salary,
  LAG(salary) OVER (ORDER BY hire_date) AS prev_salary
FROM employees;

WITH dept_avg AS (
  SELECT department, AVG(salary) AS avg_sal
  FROM employees GROUP BY department
)
SELECT * FROM dept_avg WHERE avg_sal > 50000;

CREATE TABLE orders (
  id INT PRIMARY KEY,
  customer_id INT,
  amount DECIMAL(10,2) CHECK (amount > 0),
  FOREIGN KEY (customer_id) REFERENCES customers(id)
);

BEGIN TRANSACTION;
UPDATE accounts SET balance = balance - 100 WHERE id = 1;
UPDATE accounts SET balance = balance + 100 WHERE id = 2;
COMMIT;

-- Un-normalized: repeating groups
-- orders(id, customer_name, product1, product2)

-- Normalized (1NF+): separate orders and order_items tables
CREATE TABLE orders (id INT PRIMARY KEY, customer_id INT);
CREATE TABLE order_items (order_id INT, product_id INT, qty INT);

CREATE PROCEDURE GetHighEarners(IN min_salary DECIMAL)
BEGIN
  SELECT name, salary FROM employees WHERE salary > min_salary;
END;
